/**
 * UI and utility re-exports for copy-standalone portability.
 *
 * This file centralizes dependencies so the component can be easily
 * copied to another project by updating these imports to match the target
 * project's paths.
 */
import type { ClassValue } from "clsx";
import { clsx } from "clsx";
import { twMerge } from "tailwind-merge";

export function cn(...inputs: ClassValue[]) {
  return twMerge(clsx(inputs));
}

export { Button } from "../../ui/button";
export { Card } from "../../ui/card";
export { ChevronLeft, ChevronRight } from "lucide-react";

"use client";

import { createToolUiErrorBoundary } from "../shared/error-boundary";

export const ItemCarouselErrorBoundary =
  createToolUiErrorBoundary("ItemCarousel");

export { ItemCarousel } from "./item-carousel";
export { ItemCard } from "./item-card";
export { ItemCarouselErrorBoundary } from "./error-boundary";
export type {
  Item,
  ItemCarouselProps,
  SerializableItem,
  SerializableItemCarousel,
} from "./schema";
export {
  ItemSchema,
  ItemCarouselPropsSchema,
  SerializableItemSchema,
  SerializableItemCarouselSchema,
  parseSerializableItemCarousel,
  safeParseSerializableItemCarousel,
} from "./schema";

"use client";

import * as React from "react";
import { cn, Button, Card } from "./_adapter";
import type { Item } from "./schema";

interface ItemCardProps {
  item: Item;
  onItemClick?: (itemId: string) => void;
  onItemAction?: (itemId: string, actionId: string) => void;
}

export function ItemCard({ item, onItemClick, onItemAction }: ItemCardProps) {
  const { id, name, subtitle, image, color, actions } = item;
  const isCardInteractive = typeof onItemClick === "function";

  const handleCardClick = (e: React.MouseEvent) => {
    if (!isCardInteractive) return;
    if ((e.target as HTMLElement).closest("button")) {
      return;
    }
    onItemClick?.(id);
  };

  const handleCardKeyDown = (e: React.KeyboardEvent) => {
    if (!isCardInteractive) return;
    if ((e.target as HTMLElement).closest("button")) return;

    if (e.key === " ") {
      e.preventDefault();
      return;
    }

    if (e.key === "Enter") {
      e.preventDefault();
      onItemClick?.(id);
    }
  };

  const handleCardKeyUp = (e: React.KeyboardEvent) => {
    if (!isCardInteractive) return;
    if ((e.target as HTMLElement).closest("button")) return;

    if (e.key === " ") {
      e.preventDefault();
      onItemClick?.(id);
    }
  };

  const handleActionClick = (actionId: string) => {
    onItemAction?.(id, actionId);
  };

  return (
    <Card
      className={cn(
        "group @container/card relative flex w-52 min-w-48 flex-col gap-0 self-stretch overflow-clip rounded-md p-0 @lg:w-56",
        isCardInteractive && "cursor-pointer hover:shadow",
        isCardInteractive &&
          "focus-visible:ring-ring focus-visible:ring-offset-background focus-visible:ring-2 focus-visible:ring-offset-2 focus-visible:outline-none",
        "touch-manipulation",
      )}
      role={isCardInteractive ? "button" : undefined}
      tabIndex={isCardInteractive ? 0 : undefined}
      aria-label={isCardInteractive ? `View item: ${name}` : undefined}
      onClick={isCardInteractive ? handleCardClick : undefined}
      onKeyDown={isCardInteractive ? handleCardKeyDown : undefined}
      onKeyUp={isCardInteractive ? handleCardKeyUp : undefined}
    >
      <div className="bg-muted relative aspect-square w-full overflow-hidden">
        {image ? (
          // eslint-disable-next-line @next/next/no-img-element
          <img
            src={image}
            alt={name}
            loading="lazy"
            decoding="async"
            draggable={false}
            className={cn(
              "h-full w-full object-cover transition-transform duration-200",
              isCardInteractive && "group-hover:scale-105",
            )}
          />
        ) : (
          <div
            className={cn(
              "h-full w-full transition-transform duration-200",
              isCardInteractive && "group-hover:scale-105",
            )}
            style={color ? { backgroundColor: color } : undefined}
            role="img"
            aria-label={name}
          />
        )}
      </div>

      <div className="flex flex-1 flex-col gap-1 p-3">
        <div className="flex flex-col gap-1">
          <h3 className="line-clamp-2 text-sm leading-tight font-medium">
            {name}
          </h3>

          {subtitle && (
            <p className="text-muted-foreground line-clamp-1 text-sm">
              {subtitle}
            </p>
          )}
        </div>

        {actions && actions.length > 0 && (
          <div
            className={cn(
              "mt-auto flex flex-col-reverse gap-2 pt-2 @[176px]/card:flex-row",
            )}
          >
            {actions.map((action) => (
              <Button
                key={action.id}
                type="button"
                variant={action.variant ?? "default"}
                size="sm"
                disabled={action.disabled}
                className="min-h-11 w-full px-3 md:min-h-8 @[176px]/card:h-8 @[176px]/card:w-auto @[176px]/card:flex-1"
                onClick={(e) => {
                  e.stopPropagation();
                  handleActionClick(action.id);
                }}
              >
                {action.icon}
                {action.label}
              </Button>
            ))}
          </div>
        )}
      </div>
    </Card>
  );
}

"use client";

import { useRef, useState, useEffect, useCallback } from "react";
import { cn, Button, Card, ChevronLeft, ChevronRight } from "./_adapter";
import { ItemCard } from "./item-card";
import { prefersReducedMotion } from "../shared/utils";
import type { ItemCarouselProps } from "./schema";

const SCROLL_PADDING_STYLE = { scrollPaddingInline: "1rem" };

const SCROLL_EDGE_THRESHOLD_PX = 8;
const SNAP_EPSILON_PX = 5;
const SCROLL_ANIMATION_DURATION_MS = 300;
const PAGE_SCROLL_RATIO = 0.8;
const PAGE_SCROLL_BREAKPOINT_PX = 640;

type ScrollDirection = "left" | "right";

interface ScrollAnimationState {
  target: number;
  start: number;
  startTime: number;
  duration: number;
  onComplete?: () => void;
}

function useSmoothScroll() {
  const animationRef = useRef<ScrollAnimationState | null>(null);
  const frameRef = useRef<number | null>(null);

  const cancelAnimation = useCallback(() => {
    if (frameRef.current !== null) {
      cancelAnimationFrame(frameRef.current);
      frameRef.current = null;
    }
    animationRef.current = null;
  }, []);

  useEffect(() => cancelAnimation, [cancelAnimation]);

  const scrollTo = useCallback(
    (
      element: HTMLElement,
      target: number,
      duration = SCROLL_ANIMATION_DURATION_MS,
      onComplete?: () => void,
    ) => {
      if (prefersReducedMotion() || duration <= 0) {
        element.scrollLeft = target;
        onComplete?.();
        return;
      }

      cancelAnimation();

      animationRef.current = {
        target,
        start: element.scrollLeft,
        startTime: performance.now(),
        duration,
        onComplete,
      };

      element.style.scrollSnapType = "none";

      const step = () => {
        const anim = animationRef.current;
        if (!anim) return;

        const elapsed = performance.now() - anim.startTime;
        const progress = Math.min(elapsed / anim.duration, 1);
        const eased = 1 - Math.pow(1 - progress, 3);

        element.scrollLeft = anim.start + (anim.target - anim.start) * eased;

        if (progress < 1) {
          frameRef.current = requestAnimationFrame(step);
          return;
        }

        element.scrollLeft = anim.target;
        const callback = anim.onComplete;
        cancelAnimation();

        requestAnimationFrame(() => {
          element.style.scrollSnapType = "";
          callback?.();
        });
      };

      frameRef.current = requestAnimationFrame(step);
    },
    [cancelAnimation],
  );

  const isAnimating = useCallback(
    () => animationRef.current !== null && frameRef.current !== null,
    [],
  );

  return { scrollTo, isAnimating, cancelAnimation };
}

function useScrollEdgeState(
  scrollRef: React.RefObject<HTMLDivElement | null>,
  itemCount: number,
) {
  const [canScrollLeft, setCanScrollLeft] = useState(false);
  const [canScrollRight, setCanScrollRight] = useState(false);

  const updateState = useCallback(() => {
    const container = scrollRef.current;
    if (!container) return;

    const scrollLeft = Math.round(container.scrollLeft);
    const maxScroll = Math.max(
      0,
      Math.round(container.scrollWidth - container.clientWidth),
    );

    setCanScrollLeft(scrollLeft > SCROLL_EDGE_THRESHOLD_PX);
    setCanScrollRight(scrollLeft < maxScroll - SCROLL_EDGE_THRESHOLD_PX);
  }, [scrollRef]);

  useEffect(() => {
    const container = scrollRef.current;
    if (!container) return;

    let rafId: number | null = null;

    const scheduleUpdate = () => {
      if (rafId !== null) cancelAnimationFrame(rafId);
      rafId = requestAnimationFrame(() => {
        rafId = null;
        updateState();
      });
    };

    scheduleUpdate();

    container.addEventListener("scroll", scheduleUpdate, { passive: true });
    const resizeObserver = new ResizeObserver(scheduleUpdate);
    resizeObserver.observe(container);

    return () => {
      container.removeEventListener("scroll", scheduleUpdate);
      resizeObserver.disconnect();
      if (rafId !== null) cancelAnimationFrame(rafId);
    };
  }, [scrollRef, updateState, itemCount]);

  return { canScrollLeft, canScrollRight };
}

function CarouselNavButton({
  direction,
  visible,
  onClick,
}: {
  direction: ScrollDirection;
  visible: boolean;
  onClick: () => void;
}) {
  const isLeft = direction === "left";
  const Icon = isLeft ? ChevronLeft : ChevronRight;

  return (
    <Button
      type="button"
      variant="secondary"
      size="icon-sm"
      className={cn(
        "pointer-events-none scale-90 border-none opacity-0",
        "bg-background/60 absolute inset-y-0 z-20 my-auto hidden h-[6cqh] min-h-[50px] rounded-2xl backdrop-blur-lg",
        "transition-[opacity,transform] duration-250 ease-[cubic-bezier(0.16,1,0.3,1)] motion-reduce:transition-none",
        "@md:flex",
        isLeft ? "left-1.5" : "right-1.5",
        visible &&
          "pointer-events-auto scale-100 opacity-100 @md:group-focus-within:pointer-events-auto @md:group-focus-within:scale-100 @md:group-focus-within:opacity-100 @md:group-hover:pointer-events-auto @md:group-hover:scale-100 @md:group-hover:opacity-100",
      )}
      onClick={onClick}
      aria-label={isLeft ? "Scroll left" : "Scroll right"}
      tabIndex={visible ? 0 : -1}
      aria-hidden={!visible}
    >
      <Icon className="h-4 w-4" />
    </Button>
  );
}

function ItemCarouselHeader({
  title,
  description,
}: {
  title?: string;
  description?: string;
}) {
  if (!title && !description) return null;

  return (
    <div className="px-4 pt-4 pb-1">
      {title && (
        <h3 className="text-[15px] leading-tight font-semibold tracking-tight">
          {title}
        </h3>
      )}
      {description && (
        <p className="text-muted-foreground mt-1 text-sm leading-snug">
          {description}
        </p>
      )}
    </div>
  );
}

function EmptyState({ className }: { className?: string }) {
  return (
    <Card className={cn("flex h-48 items-center justify-center", className)}>
      <p className="text-muted-foreground text-sm">No items to display</p>
    </Card>
  );
}

export function ItemCarousel({
  id,
  title,
  description,
  items,
  className,
  onItemClick,
  onItemAction,
}: ItemCarouselProps) {
  const scrollRef = useRef<HTMLDivElement>(null);
  const targetIndexRef = useRef<number | null>(null);

  const { scrollTo, isAnimating } = useSmoothScroll();
  const { canScrollLeft, canScrollRight } = useScrollEdgeState(
    scrollRef,
    items.length,
  );

  const scroll = useCallback(
    (direction: ScrollDirection) => {
      const container = scrollRef.current;
      if (!container) return;

      const paddingValue = window.getComputedStyle(container).scrollPaddingLeft;
      const scrollPaddingLeft = Number.isFinite(Number.parseFloat(paddingValue))
        ? Number.parseFloat(paddingValue)
        : 0;

      const itemElements = Array.from(
        container.querySelectorAll<HTMLElement>("[data-carousel-item]"),
      );
      if (itemElements.length === 0) return;

      const snapPositions = itemElements.map((el) =>
        Math.max(0, el.offsetLeft - scrollPaddingLeft),
      );

      const scrollLeft = Math.round(container.scrollLeft);
      let currentIndex: number;
      if (isAnimating()) {
        currentIndex = Math.min(
          targetIndexRef.current ?? 0,
          snapPositions.length - 1,
        );
      } else {
        currentIndex = snapPositions.length - 1;
        for (let i = 0; i < snapPositions.length; i++) {
          const snap = snapPositions[i];
          if (Math.abs(snap - scrollLeft) < SNAP_EPSILON_PX) {
            currentIndex = i;
            break;
          }
          if (snap > scrollLeft) {
            currentIndex = Math.max(0, i - 1);
            break;
          }
        }
      }

      const itemStep =
        itemElements.length > 1
          ? itemElements[1].offsetLeft - itemElements[0].offsetLeft
          : 0;
      const safeStep =
        itemStep > 0 ? itemStep : itemElements[0].offsetWidth || 1;

      const pageIndexStep =
        container.clientWidth >= PAGE_SCROLL_BREAKPOINT_PX
          ? Math.max(
              1,
              Math.floor(
                (container.clientWidth * PAGE_SCROLL_RATIO) / safeStep,
              ),
            )
          : 1;

      const targetIndex =
        direction === "right"
          ? Math.min(currentIndex + pageIndexStep, itemElements.length - 1)
          : Math.max(currentIndex - pageIndexStep, 0);

      targetIndexRef.current = targetIndex;
      const targetScrollLeft = snapPositions[targetIndex];

      if (Math.abs(targetScrollLeft - container.scrollLeft) > 1) {
        scrollTo(
          container,
          targetScrollLeft,
          SCROLL_ANIMATION_DURATION_MS,
          () => {
            targetIndexRef.current = null;
          },
        );
      }
    },
    [scrollTo, isAnimating],
  );

  const handleScrollLeft = useCallback(() => scroll("left"), [scroll]);
  const handleScrollRight = useCallback(() => scroll("right"), [scroll]);

  if (items.length === 0) {
    return <EmptyState className={className} />;
  }

  return (
    <div
      data-item-carousel-id={id}
      className={cn(
        "bg-background @container relative isolate w-full gap-0 overflow-hidden rounded-2xl border p-0",
        className,
      )}
    >
      <ItemCarouselHeader title={title} description={description} />

      <div className="group relative">
        <CarouselNavButton
          direction="left"
          visible={canScrollLeft}
          onClick={handleScrollLeft}
        />
        <CarouselNavButton
          direction="right"
          visible={canScrollRight}
          onClick={handleScrollRight}
        />

        <div
          ref={scrollRef}
          className={cn(
            "grid auto-cols-max grid-flow-col gap-4 overflow-x-auto overscroll-x-contain p-4",
            "snap-x snap-mandatory",
          )}
          role="list"
          style={SCROLL_PADDING_STYLE}
        >
          {items.map((item) => (
            <div
              key={item.id}
              data-carousel-item
              data-item-id={item.id}
              role="listitem"
              className="flex snap-start snap-always"
            >
              <ItemCard
                item={item}
                onItemClick={onItemClick}
                onItemAction={onItemAction}
              />
            </div>
          ))}
        </div>
      </div>
    </div>
  );
}

import { z } from "zod";
import {
  ActionSchema,
  defineToolUiContract,
  SerializableActionSchema,
  ToolUIIdSchema,
} from "../shared";

export const ItemSchema = z.object({
  id: z.string().min(1),
  name: z.string().min(1),
  subtitle: z.string().optional(),
  image: z.url().optional(),
  color: z.string().optional(),
  actions: z.array(ActionSchema).optional(),
});

export const ItemCarouselPropsSchema = z.object({
  id: ToolUIIdSchema,
  title: z.string().optional(),
  description: z.string().optional(),
  items: z.array(ItemSchema),
  className: z.string().optional(),
});

export type Item = z.infer<typeof ItemSchema>;

export type ItemCarouselProps = z.infer<typeof ItemCarouselPropsSchema> & {
  onItemClick?: (itemId: string) => void;
  onItemAction?: (itemId: string, actionId: string) => void;
};

export const SerializableItemSchema = ItemSchema.extend({
  actions: z.array(SerializableActionSchema).optional(),
});

export const SerializableItemCarouselSchema = ItemCarouselPropsSchema.extend({
  items: z.array(SerializableItemSchema),
});

export type SerializableItem = z.infer<typeof SerializableItemSchema>;
export type SerializableItemCarousel = z.infer<
  typeof SerializableItemCarouselSchema
>;

const SerializableItemCarouselSchemaContract = defineToolUiContract(
  "ItemCarousel",
  SerializableItemCarouselSchema,
);

export const parseSerializableItemCarousel: (
  input: unknown,
) => SerializableItemCarousel = SerializableItemCarouselSchemaContract.parse;

export const safeParseSerializableItemCarousel: (
  input: unknown,
) => SerializableItemCarousel | null =
  SerializableItemCarouselSchemaContract.safeParse;

"use client";

import type { Action } from "./schema";
import { cn, Button } from "./_adapter";
import { useActionButtons } from "./use-action-buttons";

export interface ActionButtonsProps {
  actions: Action[];
  onAction: (actionId: string) => void | Promise<void>;
  onBeforeAction?: (actionId: string) => boolean | Promise<boolean>;
  confirmTimeout?: number;
  align?: "left" | "center" | "right";
  className?: string;
}

export function ActionButtons({
  actions,
  onAction,
  onBeforeAction,
  confirmTimeout = 3000,
  align = "right",
  className,
}: ActionButtonsProps) {
  const { actions: resolvedActions, runAction } = useActionButtons({
    actions,
    onAction,
    onBeforeAction,
    confirmTimeout,
  });

  return (
    <div
      className={cn(
        "flex flex-col gap-3",
        "@sm/actions:flex-row @sm/actions:flex-wrap @sm/actions:items-center @sm/actions:gap-2",
        align === "left" && "@sm/actions:justify-start",
        align === "center" && "@sm/actions:justify-center",
        align === "right" && "@sm/actions:justify-end",
        className,
      )}
    >
      {resolvedActions.map((action) => {
        const label = action.currentLabel;
        const variant = action.variant || "default";

        return (
          <Button
            key={action.id}
            variant={variant}
            onClick={() => runAction(action.id)}
            disabled={action.isDisabled}
            className={cn(
              "rounded-full px-4!",
              "justify-center",
              "min-h-11 w-full text-base",
              "@sm/actions:min-h-0 @sm/actions:w-auto @sm/actions:px-3 @sm/actions:py-2 @sm/actions:text-sm",
              action.isConfirming &&
                "ring-destructive ring-2 ring-offset-2 motion-safe:animate-pulse",
            )}
            aria-label={
              action.shortcut ? `${label} (${action.shortcut})` : label
            }
          >
            {action.isLoading && (
              <svg
                className="mr-2 h-4 w-4 motion-safe:animate-spin"
                xmlns="http://www.w3.org/2000/svg"
                fill="none"
                viewBox="0 0 24 24"
              >
                <circle
                  className="opacity-25"
                  cx="12"
                  cy="12"
                  r="10"
                  stroke="currentColor"
                  strokeWidth="4"
                />
                <path
                  className="opacity-75"
                  fill="currentColor"
                  d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"
                />
              </svg>
            )}
            {action.icon && !action.isLoading && (
              <span className="mr-2">{action.icon}</span>
            )}
            {label}
            {action.shortcut && !action.isLoading && (
              <kbd className="border-border bg-muted ml-2.5 hidden rounded-lg border px-2 py-0.5 font-mono text-xs font-medium sm:inline-block">
                {action.shortcut}
              </kbd>
            )}
          </Button>
        );
      })}
    </div>
  );
}

import type { Action, ActionsConfig } from "./schema";

export type ActionsProp = ActionsConfig | Action[];

const NEGATORY_ACTION_IDS = new Set([
  "cancel",
  "dismiss",
  "skip",
  "no",
  "reset",
  "close",
  "decline",
  "reject",
  "back",
  "later",
  "not-now",
  "maybe-later",
]);

function inferVariant(action: Action): Action {
  if (action.variant) return action;
  if (NEGATORY_ACTION_IDS.has(action.id)) {
    return { ...action, variant: "ghost" };
  }
  return action;
}

export function normalizeActionsConfig(
  actions?: ActionsProp,
): ActionsConfig | null {
  if (!actions) return null;

  const rawItems = Array.isArray(actions) ? actions : (actions.items ?? []);

  if (rawItems.length === 0) {
    return null;
  }

  const items = rawItems.map(inferVariant);

  return Array.isArray(actions)
    ? { items }
    : {
        items,
        align: actions.align,
        confirmTimeout: actions.confirmTimeout,
      };
}

import { z } from "zod";
import { parseWithSchema, safeParseWithSchema } from "./parse";

export interface ToolUiContract<T> {
  schema: z.ZodType<T>;
  parse: (input: unknown) => T;
  safeParse: (input: unknown) => T | null;
}

export function defineToolUiContract<T>(
  componentName: string,
  schema: z.ZodType<T>,
): ToolUiContract<T> {
  return {
    schema,
    parse: (input: unknown) => parseWithSchema(schema, input, componentName),
    safeParse: (input: unknown) => safeParseWithSchema(schema, input),
  };
}

"use client";

import * as React from "react";

export interface ToolUIErrorBoundaryProps {
  componentName: string;
  children: React.ReactNode;
  fallback?: React.ReactNode;
  onError?: (error: Error, errorInfo: React.ErrorInfo) => void;
}

export type ToolUiComponentBoundaryProps = Omit<
  ToolUIErrorBoundaryProps,
  "componentName"
>;

interface ToolUIErrorBoundaryState {
  hasError: boolean;
  error?: Error;
}

export class ToolUIErrorBoundary extends React.Component<
  ToolUIErrorBoundaryProps,
  ToolUIErrorBoundaryState
> {
  constructor(props: ToolUIErrorBoundaryProps) {
    super(props);
    this.state = { hasError: false };
  }

  static getDerivedStateFromError(error: Error): ToolUIErrorBoundaryState {
    return { hasError: true, error };
  }

  componentDidCatch(error: Error, errorInfo: React.ErrorInfo) {
    console.error(
      `[${this.props.componentName}] render error:`,
      error,
      errorInfo,
    );
    this.props.onError?.(error, errorInfo);
  }

  render() {
    if (this.state.hasError) {
      return (
        this.props.fallback ?? (
          <div className="border-destructive text-destructive rounded-lg border p-4">
            <p className="font-semibold">
              {this.props.componentName} failed to render
            </p>
            <p className="text-sm">{this.state.error?.message}</p>
          </div>
        )
      );
    }
    return this.props.children;
  }
}

export function createToolUiErrorBoundary(componentName: string) {
  const ToolUiComponentBoundary = ({
    children,
    ...rest
  }: ToolUiComponentBoundaryProps) => (
    <ToolUIErrorBoundary componentName={componentName} {...rest}>
      {children}
    </ToolUIErrorBoundary>
  );

  ToolUiComponentBoundary.displayName = `${componentName}ErrorBoundary`;
  return ToolUiComponentBoundary;
}

